	    this._clean(articleContent, "iframe");
	    this._clean(articleContent, "input");
	    this._clean(articleContent, "textarea");
	    this._clean(articleContent, "select");
	    this._clean(articleContent, "button");
	    this._cleanHeaders(articleContent);
	
